import{a3 as e,e as o,f as t,V as a}from"./chunks/framework.-j7siyoT.js";const p=JSON.parse('{"title":"Note 2","description":"","frontmatter":{},"headers":[],"relativePath":"vue3/No.2.md","filePath":"vue3/No.2.md"}'),s={name:"vue3/No.2.md"},i=a('<h1 id="note-2" tabindex="-1">Note 2 <a class="header-anchor" href="#note-2" aria-label="Permalink to &quot;Note 2&quot;">​</a></h1><h2 id="v-if-vs-v-show​" tabindex="-1">v-if vs. v-show​ <a class="header-anchor" href="#v-if-vs-v-show​" aria-label="Permalink to &quot;v-if vs. v-show​&quot;">​</a></h2><ul><li><p><code>v-if</code> 是“真实的”按条件渲染，因为它确保了在切换时，条件区块内的事件监听器和子组件都会被销毁与重建。</p></li><li><p><code>v-if</code> 也是惰性的：如果在初次渲染时条件值为 <code>false</code>，则不会做任何事。<strong>条件区块只有当条件首次变为 <code>true</code> 时才被渲染。</strong></p></li><li><p>相比之下，<code>v-show</code> 简单许多，<strong>元素无论初始条件如何，始终会被渲染，只有 CSS display 属性会被切换</strong>。</p></li></ul><p>总的来说，<strong>v-if 有更高的切换开销，而 v-show 有更高的初始渲染开销</strong>。因此，<em><em>如果需要频繁切换，则使用 v-show 较好</em>；<em>如果在运行时绑定条件很少改变，则 v-if 会更合适</em></em>。</p>',4),r=[i];function c(n,d,l,_,v,h){return o(),t("div",null,r)}const m=e(s,[["render",c]]);export{p as __pageData,m as default};
